Below is a **compact version** you can drop into your existing `app_main.cpp` (only the new/changed parts are shown).

```cpp
/* --------------------------------------------------------------
   0️⃣  Include the extra headers we need
   -------------------------------------------------------------- */
#include <unordered_map>
#include <esp_matter_client.h>
#include <app/ConcreteAttributePath.h>
#include <app/ConcreteCommandPath.h>
#include <app/clusters/bindings/binding-table.h>
#include <platform/ESP32/CHIPDevicePlatformConfig.h>
/* -------------------------------------------------------------- */

using namespace esp_matter;
using namespace esp_matter::client;

/* --------------------------------------------------------------
   1️⃣  Global data structures for subscription tracking
   -------------------------------------------------------------- */
struct RemoteBindingKey {
    uint64_t node_id;
    uint16_t endpoint;
    bool operator==(const RemoteBindingKey &o) const {
        return node_id == o.node_id && endpoint == o.endpoint;
    }
};
struct RemoteBindingKeyHash {
    size_t operator()(const RemoteBindingKey &k) const noexcept {
        return std::hash<uint64_t>{}(k.node_id) ^ (std::hash<uint16_t>{}(k.endpoint) << 1);
    }
};
static std::unordered_map<RemoteBindingKey, chip::app::ReadClient *, RemoteBindingKeyHash> gActiveSubs;

/* --------------------------------------------------------------
   2️⃣  Subscription callback (see section 4.2)
   -------------------------------------------------------------- */
class ShadeSubscriptionCallback : public chip::app::ReadClient::Callback {
public:
    void OnAttributeData(const chip::app::ConcreteDataAttributePath &path,
                         chip::TLV::TLVReader &data,
                         const chip::app::StatusIB *status) override
    {
        if (path.mClusterId != chip::app::Clusters::BooleanState::Id ||
            path.mAttributeId != chip::app::Clusters::BooleanState::Attributes::StateValue::Id) {
            return;
        }
        bool state = false;
        if (CHIP_NO_ERROR != data.Get(state)) {
            ESP_LOGE(TAG, "TLV decode error");
            return;
        }
        ESP_LOGI(TAG, "Remote contact %s", state ? "CLOSED" : "OPEN");
        handle_remote_contact(state);
    }

    void OnError(CHIP_ERROR error) override { ESP_LOGE(TAG, "Sub error: %s", chip::ErrorStr(error)); }
    void OnDone(chip::app::ReadClient *client) override { ESP_LOGI(TAG, "Sub done"); }
};
static ShadeSubscriptionCallback gSubCb;

/* --------------------------------------------------------------
   3️⃣  Request‑send callback (section 4.1)
   -------------------------------------------------------------- */
static void request_send_cb(peer_device_t *peer, request_handle_t *req, void *priv)
{
    ESP_LOGI(TAG, "CASE ready – peer 0x%016llx", peer->GetDeviceId());

    // We ignore the request_handle content – we already know we want a subscription
    esp_err_t err = esp_matter::client::interaction::subscribe::send_request(
        peer,
        nullptr, 0,
        nullptr, 0,
        0, 60,
        true,               // keep_subscription
        true,               // auto_resubscribe
        gSubCb);
    if (err != ESP_OK) {
        ESP_LOGE(TAG, "Failed to start subscription: %s", esp_err_to_name(err));
    }
}

/* --------------------------------------------------------------
   4️⃣  Helper that starts a CASE session for a given binding entry
   -------------------------------------------------------------- */
static void subscribe_to_remote(const chip::BindingTable::Entry &e)
{
    // Build attribute path for BooleanState::StateValue on the remote side
    chip::app::AttributePathParams attr_path;
    attr_path.mEndpointId = static_cast<chip::EndpointId>(e.endpointId);
    attr_path.mClusterId  = static_cast<chip::ClusterId>(chip::app::Clusters::BooleanState::Id);
    attr_path.mFieldId    = static_cast<chip::AttributeId>(chip::app::Clusters::BooleanState::Attributes::StateValue::Id);
    attr_path.mFlags      = chip::app::AttributePathParams::Flags::kFieldIdValid;

    // Store the binding key so we can avoid duplicate subscriptions
    RemoteBindingKey key{ e.nodeId, e.endpointId };
    if (gActiveSubs.find(key) != gActiveSubs.end()) {
        ESP_LOGD(TAG, "Already subscribed to node 0x%llx ep %u", key.node_id, key.endpoint);
        return;
    }

    // Prepare a request handle – the SDK will call request_send_cb when the CASE session is up.
    request_handle_t req{};
    req.type = client::request_type_t::SUBSCRIBE_ATTR;
    req.attribute_path = attr_path;
    req.request_data = nullptr; // no extra payload

    // Remember we have a pending subscription (placeholder)
    gActiveSubs.emplace(key, nullptr);

    // Fire off the CASE session
    esp_err_t err = esp_matter::client::connect(
        esp_matter::case_session_mgr_t::GetInstance(),
        0,                 // fabric index (0 = current)
        e.nodeId,
        &req);
    if (err != ESP_OK) {
        ESP_LOGE(TAG, "connect() failed: %s", esp_err_to_name(err));
        gActiveSubs.erase(key);
    }
}

/* --------------------------------------------------------------
   5️⃣  Binding‑changed handler (section 3)
   -------------------------------------------------------------- */
static void handle_binding_changed(void)
{
    const chip::BindingTable &tbl = chip::BindingTable::GetInstance();
    size_t sz = tbl.Size();
    ESP_LOGI(TAG, "Binding table size = %zu", sz);

    // First, clean up any entries that vanished
    for (auto it = gActiveSubs.begin(); it != gActiveSubs.end(); ) {
        bool still_present = false;
        for (size_t i = 0; i < sz; ++i) {
            const auto &e = tbl[i];
            if (e.nodeId == it->first.node_id && e.endpointId == it->first.endpoint) {
                still_present = true;
                break;
            }
        }
        if (!still_present) {
            ESP_LOGI(TAG, "Binding removed – node 0x%llx ep %u", it->first.node_id, it->first.endpoint);
            // If you kept a real ReadClient* you would shut it down here.
            it = gActiveSubs.erase(it);
        } else {
            ++it;
        }
    }

    // Then, add new ones
    for (size_t i = 0; i < sz; ++i) {
        const auto &e = tbl[i];
        if (e.nodeId == 0) continue; // ignore local
        if (e.clusterId != chip::app::Clusters::BooleanState::Id) continue;
        subscribe_to_remote(e);
    }
}

/* --------------------------------------------------------------
   6️⃣  Bind‑command validator (section 7)
   -------------------------------------------------------------- */
static esp_err_t bind_command_validator(const ConcreteCommandPath &cmd_path,
                                        TLVReader &tlv_data,
                                        void *opaque_ptr)
{
    chip::Binding::Target target;
    CHIP_ERROR err = chip::Binding::ReadFromTLV(tlv_data, target);
    if (err != CHIP_NO_ERROR) {
        ESP_LOGE(TAG, "Bind payload decode error: %s", chip::ErrorStr(err));
        return ESP_ERR_INVALID_ARG;
    }

    // Only accept BooleanState::StateValue
    if (target.clusterId != chip::app::Clusters::BooleanState::Id ||
        target.attributeId != chip::app::Clusters::BooleanState::Attributes::StateValue::Id) {
        ESP_LOGW(TAG, "Reject Bind – unsupported cluster/attribute");
        return ESP_ERR_NOT_SUPPORTED;
    }

    // (Optional) you could read the remote Descriptor cluster here to make
    // sure it really is a Contact‑Sensor device type.
    ESP_LOGI(TAG, "Accept Bind – node 0x%llx ep %u", target.nodeId, target.endpointId);
    return ESP_OK;
}

/* --------------------------------------------------------------
   7️⃣  app_main – glue everything together
   -------------------------------------------------------------- */
extern "C" void app_main(void)
{
    // ---------- (unchanged) NVS, driver init, node creation … ----------
    // (your existing code up to `node_t *node = node::create(...);`)

    // ---------- 7️⃣  Create Binding cluster on root endpoint ----------
    cluster::binding::config_t bind_cfg;
    cluster::binding::create(root_node_ep, &bind_cfg, CLUSTER_FLAG_SERVER);
    // Install validator
    cluster_t *binding_cluster = cluster::binding::create(root_node_ep, &bind_cfg, CLUSTER_FLAG_SERVER);
    command_t *bind_cmd = cluster::binding::command::create_bind(binding_cluster);
    command::set_user_callback(bind_cmd, bind_command_validator);

    // ---------- 8️⃣  Register request‑send callback ----------
    esp_matter::client::set_request_callback(request_send_cb, nullptr, nullptr);

    // ---------- 9️⃣  Start Matter ----------
    esp_err_t err = esp_matter::start(app_event_cb, nullptr);
    ESP_ERROR_CHECK(err);
}
